router.get('/users', async (ctx) => {
  const queryParams = ctx.request.url.searchParams;
  const filterKey = queryParams.get('filter_by');
  const filterValue = queryParams.get('filter_value');
  const limitParam = queryParams.get('limit');
  const limit = limitParam ? parseInt(limitParam, 10) : 100;

  const users: User[] = [];
  const startKey: Deno.KvKey = ['users'];
  const endKey: Deno.KvKey = ['users', Deno.KvKeyPart.MAX];

  if (filterKey && filterValue) {
    // Construct dynamic key prefixes for indexed lookups
    let prefix: Deno.KvKey | undefined;
    let valueToUse: string | number = filterValue.toLowerCase();

    switch (filterKey) {
      case 'name':
        prefix = ['users_by_name', valueToUse];
        break;
      case 'email':
        prefix = ['users_by_email', valueToUse];
        break;
      case 'age':
        valueToUse = parseInt(filterValue, 10);
        if (isNaN(valueToUse)) {
          ctx.response.status = 400;
          ctx.response.body = { error: 'Invalid age value' };
          return;
        }
        prefix = ['users_by_age', valueToUse];
        break;
      case 'city':
        prefix = ['users_by_city', valueToUse];
        break;
      case 'country':
        prefix = ['users_by_country', valueToUse];
        break;
      default:
        ctx.response.status = 400;
        ctx.response.body = { error: `Unsupported filter_by: ${filterKey}` };
        return;
    }

    if (prefix) {
      // Use the constructed prefix for an efficient range scan
      for await (const entry of KV_STORE.list({ prefix }, { limit })) {
        users.push(entry.value as User);
      }
    }
  } else {
    // No specific filter, fetch all users from the main 'users' collection
    for await (const entry of KV_STORE.list({ start: startKey, end: endKey }, { limit })) {
      users.push(entry.value as User);
    }
  }

  ctx.response.body = users;
});

router.get('/users/:id', async (ctx) => {
  const userId = ctx.params.id;
  const userEntry = await KV_STORE.get<User>(['users', userId]);

  if (userEntry.value) {
    ctx.response.body = userEntry.value;
  } else {
    ctx.response.status = 404;
    ctx.response.body = { message: 'User not found' };
  }
});

router.post('/users', async (ctx) => {
  if (!ctx.request.hasBody) {
    ctx.response.status = 400;
    ctx.response.body = { error: 'Request body is required' };
    return;
  }

  const body = await ctx.request.body({ type: 'json' }).value;
  const newUser: User = {
    id: generateId(),
    name: body.name,
    email: body.email,
    age: body.age,
    city: body.city,
    country: body.country,
  };

  if (!newUser.name || !newUser.email || !newUser.age || !newUser.city || !newUser.country) {
    ctx.response.status = 400;
    ctx.response.body = { error: 'Missing required user fields' };
    return;
  }

  const ops = KV_STORE.atomic();
  ops.set(['users', newUser.id], newUser);
  // Add entries for efficient searching by common fields
  ops.set(['users_by_name', newUser.name.toLowerCase(), newUser.id], newUser);
  ops.set(['users_by_email', newUser.email.toLowerCase(), newUser.id], newUser);
  ops.set(['users_by_age', newUser.age, newUser.id], newUser);
  ops.set(['users_by_city', newUser.city.toLowerCase(), newUser.id], newUser);
  ops.set(['users_by_country', newUser.country.toLowerCase(), newUser.id], newUser);

  const result = await ops.commit();

  if (result.ok) {
    ctx.response.status = 201;
    ctx.response.body = newUser;
  } else {
    ctx.response.status = 500;
    ctx.response.body = { error: 'Failed to create user' };
  }
});

router.put('/users/:id', async (ctx) => {
  const userId = ctx.params.id;
  if (!ctx.request.hasBody) {
    ctx.response.status = 400;
    ctx.response.body = { error: 'Request body is required' };
    return;
  }

  const body = await ctx.request.body({ type: 'json' }).value;

  const existingUserEntry = await KV_STORE.get<User>(['users', userId]);
  if (!existingUserEntry.value) {
    ctx.response.status = 404;
    ctx.response.body = { message: 'User not found' };
    return;
  }

  const oldUser = existingUserEntry.value;
  const updatedUser: User = {
    ...oldUser,
    name: body.name ?? oldUser.name,
    email: body.email ?? oldUser.email,
    age: body.age ?? oldUser.age,
    city: body.city ?? oldUser.city,
    country: body.country ?? oldUser.country,
  };

  const ops = KV_STORE.atomic();

  // Remove old index entries if fields have changed
  if (oldUser.name !== updatedUser.name) {
    ops.delete(['users_by_name', oldUser.name.toLowerCase(), oldUser.id]);
  }
  if (oldUser.email !== updatedUser.email) {
    ops.delete(['users_by_email', oldUser.email.toLowerCase(), oldUser.id]);
  }
  if (oldUser.age !== updatedUser.age) {
    ops.delete(['users_by_age', oldUser.age, oldUser.id]);
  }
  if (oldUser.city !== updatedUser.city) {
    ops.delete(['users_by_city', oldUser.city.toLowerCase(), oldUser.id]);
  }
  if (oldUser.country !== updatedUser.country) {
    ops.delete(['users_by_country', oldUser.country.toLowerCase(), oldUser.id]);
  }

  // Set the updated main user entry
  ops.set(['users', userId], updatedUser);

  // Add new index entries for updated fields
  ops.set(['users_by_name', updatedUser.name.toLowerCase(), updatedUser.id], updatedUser);
  ops.set(['users_by_email', updatedUser.email.toLowerCase(), updatedUser.id], updatedUser);
  ops.set(['users_by_age', updatedUser.age, updatedUser.id], updatedUser);
  ops.set(['users_by_city', updatedUser.city.toLowerCase(), updatedUser.id], updatedUser);
  ops.set(['users_by_country', updatedUser.country.toLowerCase(), updatedUser.id], updatedUser);


  const result = await ops.commit();

  if (result.ok) {
    ctx.response.body = updatedUser;
  } else {
    ctx.response.status = 500;
    ctx.response.body = { error: 'Failed to update user' };
  }
});

router.delete('/users/:id', async (ctx) => {
  const userId = ctx.params.id;

  const userEntry = await KV_STORE.get<User>(['users', userId]);
  if (!userEntry.value) {
    ctx.response.status = 404;
    ctx.response.body = { message: 'User not found' };
    return;
  }
  const userToDelete = userEntry.value;

  const ops = KV_STORE.atomic();
  ops.delete(['users', userId]);
  ops.delete(['users_by_name', userToDelete.name.toLowerCase(), userId]);
  ops.delete(['users_by_email', userToDelete.email.toLowerCase(), userId]);
  ops.delete(['users_by_age', userToDelete.age, userId]);
  ops.delete(['users_by_city', userToDelete.city.toLowerCase(), userId]);
  ops.delete(['users_by_country', userToDelete.country.toLowerCase(), userId]);

  const result = await ops.commit();

  if (result.ok) {
    ctx.response.status = 204;
  } else {
    ctx.response.status = 500;
    ctx.response.body = { error: 'Failed to delete user' };
  }
});

app.use(router.routes());
app.use(router.allowedMethods());

// Error handling middleware
app.use(async (ctx, next) => {
  try {
    await next();
  } catch (err) {
    ctx.response.status = err.status || 500;
    ctx.response.body = { error: err.message || 'Internal Server Error' };
  }
});

